var history = flow.get('alertHistory') || [];
var entry = {
    time: new Date().toLocaleTimeString(),
    message: msg.payload
};
history.unshift(entry);
if (history.length > 50) history.pop();
flow.set('alertHistory', history);

var html = '<table style="width:100%;border-collapse:collapse;">';
html += '<tr style="background:#333;color:white;"><th style="padding:5px;">Time</th><th style="padding:5px;">Alert</th></tr>';
for (var i = 0; i < history.length; i++) {
    html += '<tr style="border-bottom:1px solid #555;"><td style="padding:5px;">' + history[i].time + '</td><td style="padding:5px;">' + history[i].message + '</td></tr>';
}
html += '</table>';
msg.payload = html;
return msg;
